def combine(n: int, k: int):
    res, path = [], []
    def dfs(start: int):
        if len(path) + (n - start + 1) < k:
            return
        if len(path) == k:
            res.append(path[:])
            return
        for x in range(start, n + 1):
            path.append(x)
            dfs(x + 1)
            path.pop()
    if k == 0:
        return [[]]
    dfs(1)
    return res

